INSERT INTO `comment` VALUES (1,'1123',0,33,1,0,84,0,12,1,0,'2025-01-08 10:12:49'),(2,'然后我方领主吸取教训，不再买铠甲，一人发了一身绿军装，然后从英国订购了一万支恩菲尔德1853，八百挺加特林，三十门8磅步兵炮。',0,35,0,0,84,0,0,1,0,'2025-01-08 10:31:17'),(3,'我倒是在一个无关的回答里让我想到了周星驰',0,35,0,0,84,0,0,1,0,'2025-01-08 10:44:24'),(4,'不知道写什么',0,44,1,0,84,0,0,1,0,'2025-01-08 19:26:15'),(5,'作为一个十岁孩子的母亲，我是认可这个观点的。但是我在二十多岁的时候并不知道，那个时候幻想着结婚后能过上琴瑟和鸣的生活，稀里糊涂地结了婚。对婚姻最失望的时候是在怀孕期间，但是当生完孩子后，看到老公对孩子的爱，我就忽然顿悟了，觉得只要这个男人愿意和我一起抚育孩子',0,44,0,0,84,0,0,1,0,'2025-01-08 21:50:46'),(6,'我从来不后悔生孩子，我也不认为生孩子是为了男方，我是自己想要孩子，所以我对一切都充满感恩，现在把老公作为生活上的战略合作伙伴，我觉得很幸福。',0,44,0,0,84,0,0,1,0,'2025-01-08 21:51:14'),(7,'我从来不后悔生孩子，我也不认为生孩子是为了男方，我是自己想要孩子，所以我对一切都充满感恩，现在把老公作为生活上的战略合作伙伴，我觉得很幸福。',0,44,0,0,84,0,0,1,0,'2025-01-08 21:51:39'),(8,'添加一个评论',0,49,8,0,0,0,0,1,0,'2025-02-10 16:01:53'),(11,'马斯克凌晨三点甩出神秘文件，盖茨火速删光三条推特——谁能想到两位硅谷大佬隔空斗法，竟炸出了本世纪最暴利的财富密码？',0,49,3,0,0,0,0,2,0,'2025-02-10 16:15:51'),(13,'55',0,49,0,0,0,0,0,2,0,'2025-02-10 16:42:40'),(14,'111',0,49,0,8,0,0,0,2,0,'2025-02-10 17:33:21'),(15,'要3分钟，这都大幅度缩短了开发验证周期',0,49,0,8,0,0,0,2,0,'2025-02-10 17:35:08'),(16,'要3分钟，这都大幅度缩短了开发验证周期',0,49,0,8,0,0,0,1,0,'2025-02-10 17:35:28'),(17,'222',0,49,0,8,0,0,0,2,0,'2025-02-10 17:35:43'),(18,'222',0,49,0,11,0,0,0,1,0,'2025-02-10 17:36:05'),(19,'测试',0,48,3,0,0,0,0,2,0,'2025-02-10 17:36:16'),(20,'测试',0,48,0,19,0,0,0,2,0,'2025-02-10 17:36:20'),(21,'222',0,49,0,8,0,0,0,1,0,'2025-02-10 17:42:43'),(22,'333',0,49,0,11,0,0,0,1,0,'2025-02-10 17:43:08'),(23,'吃的啥',0,47,2,0,0,0,0,2,0,'2025-02-10 17:44:12'),(24,'苹果',0,47,0,23,0,0,0,1,0,'2025-02-10 17:44:18'),(25,'1111',0,49,0,8,0,0,0,2,0,'2025-02-10 19:39:17'),(26,'333',0,49,0,11,0,0,0,2,0,'2025-02-10 19:39:31'),(27,'还有啥',0,47,0,23,0,0,0,0,0,'2025-02-10 19:40:21'),(28,'测试2',0,48,0,19,0,0,0,0,0,'2025-02-10 20:43:39'),(29,'测试',0,48,5,0,0,0,0,0,0,'2025-02-10 20:43:49'),(30,'测试2',0,48,0,29,0,0,0,0,0,'2025-02-10 20:43:55'),(31,'测试2',0,48,0,29,0,0,0,0,0,'2025-02-10 20:43:56'),(32,'测试2',0,48,0,29,0,0,0,0,0,'2025-02-10 20:43:56'),(33,'测试2',0,48,0,29,0,0,0,0